
.videos {
  display: flex;
  flex-direction: column;
  gap: 9px;
}

.video {
  background: rgba(255, 255, 255, 0.78);
  border: 1.5px solid var(--sn-card-line);
  border-radius: var(--sn-radius);
  overflow: hidden;
  transition: box-shadow 0.25s ease;
}

.video.open {
  box-shadow: 0 6px 16px rgba(154, 130, 216, 0.24);
}

.video-head {
  width: 100%;
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 12px;
  border: none;
  background: transparent;
  cursor: pointer;
  font-family: var(--sn-font);
  text-align: left;
}

.thumb {
  flex-shrink: 0;
  width: 38px;
  height: 38px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.15rem;
  background: linear-gradient(135deg, #d9c8ff, #f3b6dc);
  border-radius: 11px;
}

.video-main {
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 3px;
}

.video-title {
  font-size: 0.88rem;
  font-weight: 800;
  color: var(--sn-text);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.video-time {
  font-size: 0.68rem;
  color: var(--sn-text-soft);
}

.plays {
  flex-shrink: 0;
  font-size: 0.72rem;
  font-weight: 700;
  color: var(--sn-lav-deep);
  background: rgba(185, 164, 236, 0.18);
  padding: 4px 11px;
  border-radius: 999px;
}

.v-chevron {
  flex-shrink: 0;
  color: var(--sn-lav-deep);
  font-size: 1rem;
  transition: transform 0.35s cubic-bezier(0.22, 1, 0.36, 1);
}

.video.open .v-chevron {
  transform: rotate(180deg);
}

.video-body {
  display: grid;
  grid-template-rows: 0fr;
  transition: grid-template-rows 0.38s cubic-bezier(0.22, 1, 0.36, 1);
}

.video.open .video-body {
  grid-template-rows: 1fr;
}

.video-inner {
  overflow: hidden;
}

.video-pad {
  padding: 2px 12px 13px;
  display: flex;
  flex-direction: column;
  gap: 11px;
}

.video-intro {
  font-size: 0.78rem;
  line-height: 1.5;
  color: var(--sn-text);
  padding: 8px 11px;
  background: rgba(185, 164, 236, 0.12);
  border: 1px solid var(--sn-card-line);
  border-radius: var(--sn-radius-sm);
}

.cast {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.cast-pill {
  font-size: 0.72rem;
  font-weight: 700;
  color: #fff;
  background: linear-gradient(120deg, var(--sn-lav), var(--sn-peri));
  border: none;
  padding: 5px 13px;
  border-radius: 999px;
  box-shadow: 0 2px 6px rgba(154, 130, 216, 0.3);
}

.content-row {
  display: flex;
  flex-wrap: wrap;
  gap: 9px;
}

.content-box {
  flex: 1 1 210px;
  min-width: 0;
  display: flex;
  flex-direction: column;
  background: rgba(255, 255, 255, 0.85);
  border: 1.5px solid var(--sn-card-line);
  border-radius: var(--sn-radius);
  overflow: hidden;
}

.content-body {
  padding: 14px 12px;
  min-height: 64px;
  font-size: 0.8rem;
  line-height: 1.55;
  color: var(--sn-text);
}

.content-foot {
  display: flex;
  border-top: 1.5px solid var(--sn-card-line);
}

.cf-cell {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
  padding: 8px 6px;
}

.cf-cell:first-child {
  border-right: 1.5px solid var(--sn-card-line);
}

.cf-key {
  font-size: 0.64rem;
  color: var(--sn-text-soft);
}

.cf-val {
  font-size: 0.78rem;
  font-weight: 700;
  color: var(--sn-text);
}

.quotes {
  flex: 1 1 150px;
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.quote-bubble {
  display: flex;
  flex-direction: column;
  gap: 3px;
  position: relative;
  font-size: 0.74rem;
  line-height: 1.45;
  color: var(--sn-lav-deep);
  background: rgba(255, 255, 255, 0.92);
  border: 1.5px solid var(--sn-lav);
  border-radius: 12px;
  padding: 7px 10px;
}

.quote-speaker {
  align-self: flex-start;
  color: #fff;
  background: linear-gradient(120deg, var(--sn-lav), var(--sn-peri));
  border-radius: 999px;
  padding: 1px 7px;
  font-size: 0.66rem;
  font-weight: 700;
}

.quote-text {
  color: var(--sn-lav-deep);
}

.sub-head {
  display: block;
  font-size: 0.78rem;
  font-weight: 700;
  color: var(--sn-lav-deep);
  margin-bottom: 6px;
}

.sub-head i {
  font-style: normal;
  color: var(--sn-text-faint);
  font-weight: 600;
}

.comments {
  display: flex;
  flex-direction: column;
  gap: 9px;
}

.comment {
  padding: 10px 11px;
  background: rgba(233, 224, 251, 0.45);
  border: 1px solid var(--sn-card-line);
  border-radius: 13px;
}

.comment-head {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 7px;
}

.comment-avatar {
  flex-shrink: 0;
  width: 26px;
  height: 26px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.8rem;
  background: radial-gradient(circle at 35% 30%, #d9c8ff, #a98fe0);
  border-radius: 50%;
}

.comment-id {
  display: flex;
  flex-direction: column;
  line-height: 1.25;
}

.comment-user {
  font-size: 0.78rem;
  font-weight: 700;
  color: var(--sn-text);
}

.comment-time {
  font-size: 0.64rem;
  color: var(--sn-text-soft);
}

.comment-text {
  font-size: 0.76rem;
  line-height: 1.5;
  color: var(--sn-text);
  padding: 7px 10px;
  background: #fff;
  border: 1px solid var(--sn-card-line);
  border-radius: 9px;
}

.comment-reply {
  margin-top: 7px;
  padding-left: 14px;
  border-left: 2px solid var(--sn-lav);
}

.reply-time {
  display: block;
  font-size: 0.64rem;
  color: var(--sn-lav);
  margin-bottom: 4px;
}

.reply-box {
  font-size: 0.76rem;
  line-height: 1.5;
  color: var(--sn-lav-deep);
  font-weight: 600;
  padding: 7px 10px;
  background: rgba(185, 164, 236, 0.12);
  border: 1.5px solid var(--sn-lav);
  border-radius: 9px;
}

.tips {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.tip {
  font-size: 0.72rem;
  color: var(--sn-text);
  background: linear-gradient(120deg, rgba(255, 217, 122, 0.28), rgba(243, 182, 220, 0.22));
  border: 1px solid rgba(255, 217, 122, 0.5);
  padding: 3px 9px;
  border-radius: 999px;
}

.tip b {
  color: #c79a2e;
}

.mini-empty {
  font-size: 0.72rem;
  font-style: italic;
  color: var(--sn-text-faint);
  padding: 4px 2px;
}

.empty {
  text-align: center;
  font-size: 0.8rem;
  font-style: italic;
  color: var(--sn-text-faint);
  padding: 18px 12px;
}

.blank {
  color: var(--sn-text-faint);
  font-style: italic;
  font-weight: 600;
}
